112	        const auto kernel_signature = fmt::format("{}$${}$${}$${}", name, signature, flags, code);
113	        const auto dir_path = cache_dir_path / "cache" / fmt::format("kernel.{}.{}", name, get_hex_digest(kernel_signature));
