21	    const auto c_str = std::getenv(name.c_str());
22	    if (c_str == nullptr)
23	        return default_value;
24	
25	    // Read the env and convert to the desired type
26	    if constexpr (std::is_same_v<dtype_t, std::string>) {
27	        return std::string(c_str);
28	    } else if constexpr (std::is_same_v<dtype_t, int>) {
29	        int value;
30	        std::sscanf(c_str, "%d", &value);
31	        return value;
32	    } else {
33	        EP_HOST_ASSERT(false and "Unexpected type");
34	    }
