37	static std::tuple<int, std::string> call_external_command(std::string command) {
38	    command = command + " 2>&1";
39	    const auto deleter = [](FILE* f) { if (f) pclose(f); };
40	    std::unique_ptr<FILE, decltype(deleter)> pipe(popen(command.c_str(), "r"), deleter);
41	    EP_HOST_ASSERT(pipe != nullptr);
42	
43	    std::array<char, 512> buffer;
44	    std::string output;
45	    while (fgets(buffer.data(), buffer.size(), pipe.get()))
46	        output += buffer.data();
47	    const auto status = pclose(pipe.release());
48	    // NOTES: if the child was killed by a signal (e.g., SIGINT from Ctrl+C),
49	    // WEXITSTATUS would incorrectly return 0. Treat signal death as failure.
50	    const auto exit_code = WIFEXITED(status) ? WEXITSTATUS(status) : 128 + WTERMSIG(status);
51	    return {exit_code, output};
52	}
53	
54	static std::filesystem::path make_dirs(const std::filesystem::path& path) {
55	    // OK if existed
56	    std::error_code capture;
57	    const bool created = std::filesystem::create_directories(path, capture);
58	    if (not (created or capture.value() == 0)) {
59	        EP_HOST_UNREACHABLE(fmt::format("Failed to make directory: {}, created: {}, value: {}",
60	                                        path.c_str(), created, capture.value()));
61	    }
62	    if (created and get_env<int>("EP_JIT_DEBUG"))
63	        printf("Create directory: %s\n", path.c_str());
64	    return path;
65	}
66	
67	static std::string get_uuid() {
68	    static std::random_device rd;
69	    static std::mt19937 gen([]() {
70	        return rd() ^ std::chrono::steady_clock::now().time_since_epoch().count();
71	    }());
72	    static std::uniform_int_distribution<uint32_t> dist;
73	
74	    std::stringstream ss;
75	    ss << getpid() << "-"
76	       << std::hex << std::setfill('0')
77	       << std::setw(8) << dist(gen) << "-"
78	       << std::setw(8) << dist(gen) << "-"
79	       << std::setw(8) << dist(gen);
80	    return ss.str();
81	}
82	
83	static void safe_remove_all(const std::filesystem::path& path) {
84	    std::error_code ec;
85	    if (not std::filesystem::exists(path, ec) or ec)
86	        return;
87	
88	    // A single file
89	    if (not std::filesystem::is_directory(path, ec) or ec) {
90	        std::filesystem::remove(path, ec);
91	        return;
92	    }
93	
94	    // Remove directory
95	    auto it = std::filesystem::directory_iterator(path,
96	        std::filesystem::directory_options::skip_permission_denied, ec);
97	    for (auto end = std::filesystem::directory_iterator(); it != end and not ec;) {
98	        const auto entry_path = it->path();
99	
100	        // Increase firstly to avoid failures
101	        it.increment(ec);
102	        if (ec)
103	            break;
104	
105	        // Recursively clean
106	        safe_remove_all(entry_path);
107	    }
108	    std::filesystem::remove(path, ec);
109	}
